from __future__ import annotations

import re
from dataclasses import dataclass
from datetime import date
from decimal import Decimal, InvalidOperation
from pathlib import Path
from typing import Any

from app.schemas.patch_plan import PatchPlan
from app.services.patcher.atomic import atomic_write_text

_DATE_RE = re.compile(r"\b(20\d{2}-\d{2}-\d{2})\b")
_MONEY_RE = re.compile(r"(?:€\s*)?(-?\d+(?:[.\s]\d{3})*(?:,\d{2}|\.\d{2}))\s*(?:€|EUR)?")
_BULLET_STATUS_RE = re.compile(r"^\s*-\s*(?P<status>[🔴🟡🟢])")


@dataclass(frozen=True)
class ConflictIssue:
    file: str
    section: str
    key: str
    reason: str
    existing: str
    incoming: str


def scan_patch_plan_conflicts(
    plan: PatchPlan,
    *,
    wiki_dir: Path,
    date_drift_days: int = 3,
    amount_delta_ratio: Decimal = Decimal("0.10"),
) -> tuple[PatchPlan, list[ConflictIssue]]:
    kept_ops: list[dict[str, Any]] = []
    issues: list[ConflictIssue] = []
    property_root = wiki_dir / plan.property_id

    for op in plan.ops:
        op_data = op.model_dump(exclude_none=True)
        issue = _conflict_for_op(
            op_data,
            property_root=property_root,
            date_drift_days=date_drift_days,
            amount_delta_ratio=amount_delta_ratio,
        )
        if issue is None:
            kept_ops.append(op_data)
        else:
            issues.append(issue)

    if issues:
        append_conflicts(property_root, issues)

    data = plan.model_dump()
    data["ops"] = kept_ops
    return PatchPlan.model_validate(data), issues


def append_conflicts(property_root: Path, issues: list[ConflictIssue]) -> None:
    if not issues:
        return
    path = property_root / "_pending_review.md"
    text = path.read_text(encoding="utf-8") if path.exists() else _default_pending_review()
    marker = "\n# Human Notes"
    boundary = text.find(marker)
    suffix = text[boundary:] if boundary != -1 else "\n# Human Notes\n"
    body = text[:boundary].rstrip() if boundary != -1 else text.rstrip()
    entries = []
    for issue in issues:
        entries.append(
            "\n".join(
                [
                    "",
                    f"### conflict: {issue.key}",
                    f"- file: `{issue.file}`",
                    f"- section: `{issue.section}`",
                    f"- reason: {issue.reason}",
                    f"- existing: `{issue.existing}`",
                    f"- incoming: `{issue.incoming}`",
                    "",
                ]
            )
        )
    atomic_write_text(path, body + "\n" + "\n".join(entries) + suffix)


def _conflict_for_op(
    op: dict[str, Any],
    *,
    property_root: Path,
    date_drift_days: int,
    amount_delta_ratio: Decimal,
) -> ConflictIssue | None:
    if op.get("op") not in {"upsert_bullet", "upsert_row"}:
        return None
    file = str(op.get("file", ""))
    section = str(op.get("section", ""))
    key = str(op.get("key", ""))
    if not file or not section or not key:
        return None
    path = property_root / file
    if not path.is_file():
        return None
    existing = _existing_keyed_line(path.read_text(encoding="utf-8"), section=section, key=key)
    if existing is None:
        return None
    incoming = _incoming_line(op)
    reason = _conflict_reason(
        existing,
        incoming,
        date_drift_days=date_drift_days,
        amount_delta_ratio=amount_delta_ratio,
    )
    if reason is None:
        return None
    return ConflictIssue(
        file=file,
        section=section,
        key=key,
        reason=reason,
        existing=existing,
        incoming=incoming,
    )


def _existing_keyed_line(content: str, *, section: str, key: str) -> str | None:
    body = _section_body(content, section)
    if body is None:
        return None
    bullet_key = re.compile(rf"\*\*{re.escape(key)}:\*\*")
    for line in body.splitlines():
        if line.lstrip().startswith("- ") and bullet_key.search(line):
            return line.strip()
        if line.lstrip().startswith("|") and _row_key(line) == key:
            return line.strip()
    return None


def _section_body(content: str, section: str) -> str | None:
    managed = content.split("\n# Human Notes", 1)[0]
    match = re.search(rf"^## {re.escape(section)}\s*$", managed, flags=re.MULTILINE)
    if match is None:
        return None
    next_match = re.search(r"^## .*$", managed[match.end() :], flags=re.MULTILINE)
    end = len(managed) if next_match is None else match.end() + next_match.start()
    return managed[match.end() : end]


def _row_key(line: str) -> str | None:
    cells = [cell.strip() for cell in line.strip().strip("|").split("|")]
    if not cells or set(cells[0]) <= {"-"}:
        return None
    return cells[0]


def _incoming_line(op: dict[str, Any]) -> str:
    if op.get("op") == "upsert_bullet":
        text = str(op.get("text") or op.get("content") or "")
        if text.lstrip().startswith("- "):
            return text.strip()
        key = str(op.get("key", ""))
        return f"- **{key}:** {text.strip()}"
    row = op.get("row") or op.get("content") or ""
    if isinstance(row, list):
        return "| " + " | ".join(str(cell).strip() for cell in row) + " |"
    return str(row).strip()


def _conflict_reason(
    existing: str,
    incoming: str,
    *,
    date_drift_days: int,
    amount_delta_ratio: Decimal,
) -> str | None:
    old_status = _status(existing)
    new_status = _status(incoming)
    if old_status == "🔴" and new_status == "🟢":
        return "status flip requires human approval"

    old_date = _first_date(existing)
    new_date = _first_date(incoming)
    if (
        old_date is not None
        and new_date is not None
        and abs((new_date - old_date).days) > date_drift_days
    ):
        return f"date drift exceeds {date_drift_days} days"

    old_amount = _first_amount(existing)
    new_amount = _first_amount(incoming)
    if old_amount is not None and new_amount is not None and old_amount != 0:
        delta = abs(new_amount - old_amount) / abs(old_amount)
        if delta > amount_delta_ratio:
            return f"amount delta exceeds {amount_delta_ratio:.0%}"
    return None


def _status(line: str) -> str | None:
    match = _BULLET_STATUS_RE.match(line)
    return match.group("status") if match is not None else None


def _first_date(line: str) -> date | None:
    match = _DATE_RE.search(line)
    if match is None:
        return None
    try:
        return date.fromisoformat(match.group(1))
    except ValueError:
        return None


def _first_amount(line: str) -> Decimal | None:
    for match in _MONEY_RE.finditer(line):
        raw = match.group(1).replace(" ", "")
        if raw.count(",") == 1:
            raw = raw.replace(".", "").replace(",", ".")
        try:
            return Decimal(raw)
        except InvalidOperation:
            continue
    return None


def _default_pending_review() -> str:
    return (
        "---\n"
        "name: pending-review\n"
        "description: Open conflicts awaiting PM resolution.\n"
        "---\n\n"
        "## Open Conflicts\n\n"
        "<!-- agent-managed: one ### entry per conflict -->\n\n"
        "# Human Notes\n"
    )

from __future__ import annotations

import json
import subprocess
from collections.abc import Mapping
from dataclasses import dataclass
from pathlib import Path
from typing import Any, cast

from app.services.patcher.atomic import atomic_write_text
from app.services.patcher.ops import (
    delete_bullet,
    delete_row,
    gc_footnotes,
    prepend_row,
    prune_ring,
    update_state,
    upsert_bullet,
    upsert_footnote,
    upsert_row,
)
from app.services.patcher.validate import (
    append_pending_review,
    parse_vocabulary,
    validate_keyed_values,
)
from app.services.reindex import reindex_files


@dataclass(frozen=True)
class PatchApplyResult:
    event_id: str
    applied_ops: int
    deferred_ops: int
    commit_sha: str | None
    idempotent: bool = False


def apply_patch_plan(
    plan: Mapping[str, Any],
    *,
    wiki_dir: Path,
    vocabulary_path: Path,
    wiki_chunks_db_path: Path | None = None,
) -> PatchApplyResult:
    event_id = str(plan["event_id"])
    property_id = str(plan["property_id"])
    property_root = wiki_dir / property_id
    feedback_path = property_root / "_hermes_feedback.jsonl"

    if _feedback_contains_event(feedback_path, event_id):
        return PatchApplyResult(
            event_id=event_id,
            applied_ops=0,
            deferred_ops=0,
            commit_sha=_head_sha(wiki_dir),
            idempotent=True,
        )

    ops = [op for op in plan.get("ops", []) if isinstance(op, dict)]
    vocabulary = parse_vocabulary(vocabulary_path)
    valid_ops, issues = validate_keyed_values(ops, vocabulary)
    append_pending_review(property_root, issues)

    touched: set[Path] = set()
    for op in valid_ops:
        touched.update(_apply_one(property_root, op))

    _append_feedback(feedback_path, plan, applied_ops=len(valid_ops), deferred_ops=len(issues))
    touched.add(feedback_path)
    if issues:
        touched.add(property_root / "_pending_review.md")

    commit_sha = _git_commit(
        wiki_dir,
        message=f"ingest({event_id}): {str(plan.get('summary', 'patch')).strip()}",
    )
    if wiki_chunks_db_path is not None:
        _reindex_touched_files(
            wiki_dir=wiki_dir,
            property_id=property_id,
            property_root=property_root,
            touched=touched,
            db_path=wiki_chunks_db_path,
        )
    return PatchApplyResult(
        event_id=event_id,
        applied_ops=len(valid_ops),
        deferred_ops=len(issues),
        commit_sha=commit_sha,
    )


def _apply_one(property_root: Path, op: Mapping[str, Any]) -> set[Path]:
    op_name = str(op["op"])
    if op_name == "update_state":
        path = property_root / str(op.get("file", "_state.json"))
        state = update_state(
            path,
            updates=_mapping_or_none(op.get("updates")),
            counters=_mapping_or_none(op.get("counters")),
        )
        atomic_write_text(path, json.dumps(state, indent=2, ensure_ascii=False) + "\n")
        return {path}

    file_path = property_root / str(op["file"])
    content = file_path.read_text(encoding="utf-8")
    section = str(op.get("section", ""))

    if op_name == "upsert_bullet":
        content = upsert_bullet(
            content,
            section=section,
            key=str(op["key"]),
            text=str(op["text"]),
        )
    elif op_name == "delete_bullet":
        content = delete_bullet(content, section=section, key=str(op["key"]))
    elif op_name == "upsert_row":
        content = upsert_row(
            content,
            section=section,
            key=str(op["key"]),
            row=op["row"],
            header=_sequence_or_none(op.get("header")),
        )
    elif op_name == "delete_row":
        content = delete_row(content, section=section, key=str(op["key"]))
    elif op_name == "prepend_row":
        content = prepend_row(
            content,
            section=section,
            row=op["row"],
            header=_sequence_or_none(op.get("header")),
        )
    elif op_name == "prune_ring":
        content = prune_ring(content, section=section, max_rows=int(op["max_rows"]))
    elif op_name == "upsert_footnote":
        content = upsert_footnote(content, key=str(op["key"]), text=str(op["text"]))
    elif op_name == "gc_footnotes":
        content = gc_footnotes(content, ref_counts=_mapping_or_none(op.get("ref_counts")))
    else:
        raise ValueError(f"unknown patch op: {op_name}")

    atomic_write_text(file_path, content)
    return {file_path}


def _sequence_or_none(value: object) -> list[object] | None:
    if value is None:
        return None
    if isinstance(value, list):
        return cast("list[object]", value)
    if isinstance(value, tuple):
        return list(value)
    return [value]


def _mapping_or_none(value: object) -> dict[str, Any] | None:
    if value is None:
        return None
    if isinstance(value, dict):
        return cast("dict[str, Any]", value)
    raise TypeError(f"expected mapping, got {type(value).__name__}")


def _append_feedback(
    path: Path,
    plan: Mapping[str, Any],
    *,
    applied_ops: int,
    deferred_ops: int,
) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    existing = path.read_text(encoding="utf-8") if path.exists() else ""
    record = {
        "kind": "ingest",
        "event_id": plan["event_id"],
        "property_id": plan["property_id"],
        "summary": plan.get("summary", ""),
        "applied_ops": applied_ops,
        "deferred_ops": deferred_ops,
    }
    atomic_write_text(path, existing + json.dumps(record, ensure_ascii=False) + "\n")


def _feedback_contains_event(path: Path, event_id: str) -> bool:
    if not path.exists():
        return False
    for line in path.read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError:
            continue
        if record.get("event_id") == event_id:
            return True
    return False


def _git(args: list[str], cwd: Path, *, check: bool = True) -> subprocess.CompletedProcess[str]:
    return subprocess.run(  # noqa: S603
        ["git", *args],  # noqa: S607
        cwd=cwd,
        check=check,
        capture_output=True,
        text=True,
    )


def _git_commit(wiki_dir: Path, *, message: str) -> str | None:
    _git(["add", "-A"], cwd=wiki_dir)
    diff = _git(["diff", "--cached", "--quiet"], cwd=wiki_dir, check=False)
    if diff.returncode == 0:
        return _head_sha(wiki_dir)
    if diff.returncode != 1:
        raise subprocess.CalledProcessError(diff.returncode, diff.args, diff.stdout, diff.stderr)
    _git(["commit", "-m", message], cwd=wiki_dir)
    return _head_sha(wiki_dir)


def _head_sha(wiki_dir: Path) -> str | None:
    result = _git(["rev-parse", "HEAD"], cwd=wiki_dir, check=False)
    if result.returncode != 0:
        return None
    return result.stdout.strip()


def _reindex_touched_files(
    *,
    wiki_dir: Path,
    property_id: str,
    property_root: Path,
    touched: set[Path],
    db_path: Path,
) -> None:
    files = []
    for path in touched:
        if path.suffix != ".md":
            continue
        try:
            files.append(path.relative_to(property_root))
        except ValueError:
            continue
    if files:
        reindex_files(wiki_dir=wiki_dir, property_id=property_id, files=files, db_path=db_path)

from __future__ import annotations

import re
from collections.abc import Iterable, Mapping
from dataclasses import dataclass
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

from app.services.patcher.atomic import atomic_write_text


@dataclass(frozen=True)
class ValidationIssue:
    op: Mapping[str, Any]
    reason: str


def parse_vocabulary(path: Path) -> dict[str, set[str]]:
    text = path.read_text(encoding="utf-8")
    vocab: dict[str, set[str]] = {}
    heading: str | None = None

    for raw_line in text.splitlines():
        line = raw_line.strip()
        if line.startswith("## "):
            heading = line[3:].split("(", 1)[0].strip().lower()
            continue
        if heading is None:
            continue
        values = set(re.findall(r"`([^`]+)`", line))
        if not values:
            continue
        for key in _field_names_for_heading(heading):
            vocab.setdefault(key, set()).update(values)
    return vocab


def _field_names_for_heading(heading: str) -> set[str]:
    names = {heading.replace(" ", "_").replace("-", "_")}
    if "status" in heading or "lifecycle" in heading:
        names.add("status")
    if "priority" in heading:
        names.add("priority")
    if "event type" in heading:
        names.add("event_type")
    if "risk" in heading:
        names.add("risk")
    if "confidence" in heading:
        names.add("confidence")
    if "signal" in heading:
        names.add("signal")
    if "patcher op names" in heading:
        names.add("op")
    return names


def validate_keyed_values(
    ops: Iterable[Mapping[str, Any]],
    vocabulary: Mapping[str, set[str]],
) -> tuple[list[Mapping[str, Any]], list[ValidationIssue]]:
    valid_ops: list[Mapping[str, Any]] = []
    issues: list[ValidationIssue] = []
    for op in ops:
        reason = _invalid_reason(op, vocabulary)
        if reason is None:
            valid_ops.append(op)
        else:
            issues.append(ValidationIssue(op=op, reason=reason))
    return valid_ops, issues


def _invalid_reason(op: Mapping[str, Any], vocabulary: Mapping[str, set[str]]) -> str | None:
    for field, value in _iter_keyed_values(op):
        allowed = vocabulary.get(field)
        if allowed is None:
            continue
        if _matches_allowed(str(value), allowed):
            continue
        return f"unknown vocab: {field}={value!r}"
    return None


def _iter_keyed_values(op: Mapping[str, Any]) -> Iterable[tuple[str, object]]:
    for field, value in op.items():
        if isinstance(value, dict):
            for subfield, subvalue in value.items():
                yield str(subfield), subvalue
        elif field in {"values", "fields"}:
            continue
        else:
            yield str(field), value


def _matches_allowed(value: str, allowed: set[str]) -> bool:
    if value in allowed:
        return True
    for candidate in allowed:
        if "<N>" in candidate:
            pattern = re.escape(candidate).replace(r"<N>", r"\d+")
            if re.fullmatch(pattern, value):
                return True
    return False


def append_pending_review(property_root: Path, issues: Iterable[ValidationIssue]) -> None:
    issues = list(issues)
    if not issues:
        return
    path = property_root / "_pending_review.md"
    text = path.read_text(encoding="utf-8") if path.exists() else _default_pending_review()
    marker = "\n# Human Notes"
    boundary = text.find(marker)
    if boundary == -1:
        boundary = len(text)
        suffix = "\n# Human Notes\n"
    else:
        suffix = text[boundary:]

    entries = []
    now = datetime.now(UTC).isoformat()
    for issue in issues:
        op_name = issue.op.get("op", "unknown")
        entries.append(
            "\n".join(
                [
                    "",
                    f"### {now} vocab validation failed",
                    f"- reason: {issue.reason}",
                    f"- op: `{op_name}`",
                    f"- payload: `{dict(issue.op)}`",
                    "",
                ]
            )
        )
    atomic_write_text(path, text[:boundary].rstrip() + "\n" + "\n".join(entries) + suffix)


def _default_pending_review() -> str:
    return (
        "---\n"
        "name: pending-review\n"
        "description: Open conflicts awaiting PM resolution.\n"
        "---\n\n"
        "## Open Conflicts\n\n"
        "<!-- agent-managed: one ### entry per conflict -->\n\n"
        "# Human Notes\n"
    )

from __future__ import annotations

import hashlib
from collections.abc import Mapping
from typing import Annotated, Protocol

import httpx
from fastapi import Depends

from app.core.config import REPO_ROOT, Settings, get_settings


class LLMClient(Protocol):
    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        """Return raw model text for a single prompt."""


def prompt_hash(prompt: str) -> str:
    return hashlib.sha256(prompt.encode("utf-8")).hexdigest()


class AnthropicClient:
    """Minimal Anthropic Messages API client used behind the LLMClient protocol."""

    def __init__(
        self,
        *,
        api_key: str,
        timeout: float = 60.0,
        base_url: str = "https://api.anthropic.com/v1/messages",
    ) -> None:
        self._api_key = api_key
        self._timeout = timeout
        self._base_url = base_url

    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        headers = {
            "x-api-key": self._api_key,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        }
        payload = {
            "model": model,
            "max_tokens": 4096,
            "system": [
                {
                    "type": "text",
                    "text": system_prompt,
                    "cache_control": {"type": "ephemeral"},
                }
            ],
            "messages": [{"role": "user", "content": user_prompt}],
        }
        async with httpx.AsyncClient(timeout=self._timeout) as client:
            response = await client.post(self._base_url, headers=headers, json=payload)
            response.raise_for_status()
        data = response.json()
        return "".join(
            block.get("text", "")
            for block in data.get("content", [])
            if isinstance(block, Mapping) and block.get("type") == "text"
        )


class FakeLLMClient:
    """Offline LLM test double keyed by (model, prompt_hash(user_prompt))."""

    def __init__(self, responses: Mapping[object, str] | None = None) -> None:
        self.responses = dict(responses or {})
        self.calls: list[dict[str, str]] = []

    def add_response(self, *, model: str, user_prompt: str, response: str) -> None:
        self.responses[(model, prompt_hash(user_prompt))] = response

    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        self.calls.append(
            {
                "model": model,
                "system_hash": prompt_hash(system_prompt),
                "prompt_hash": prompt_hash(user_prompt),
                "user_prompt": user_prompt,
            }
        )
        keys = (
            (model, prompt_hash(user_prompt)),
            (model, user_prompt),
            prompt_hash(user_prompt),
            model,
            "*",
        )
        for key in keys:
            if key in self.responses:
                return self.responses[key]
        return (
            '{"event_id":"","property_id":"LIE-001","summary":"fake empty plan",'
            '"ops":[],"review_items":[]}'
        )


def _system_prompt() -> str:
    return (REPO_ROOT / "schema" / "CLAUDE.md").read_text(encoding="utf-8")


def get_llm_client(
    settings: Annotated[Settings, Depends(get_settings)],
) -> LLMClient:
    if settings.anthropic_api_key is None:
        return FakeLLMClient()
    return AnthropicClient(api_key=settings.anthropic_api_key)

from __future__ import annotations

from pathlib import Path

import duckdb

from app.storage.db import connect

_SCHEMA_SQL = """
CREATE TABLE IF NOT EXISTS event_idempotency (
    event_id VARCHAR PRIMARY KEY,
    received_at TIMESTAMP DEFAULT current_timestamp,
    status VARCHAR NOT NULL DEFAULT 'pending'
)
"""


class IdempotencyStore:
    def __init__(self, conn: duckdb.DuckDBPyConnection) -> None:
        self._conn = conn

    def init_schema(self) -> None:
        self._conn.execute(_SCHEMA_SQL)

    def claim(self, event_id: str) -> bool:
        before = self._conn.execute(
            "SELECT COUNT(*) FROM event_idempotency WHERE event_id = ?",
            [event_id],
        ).fetchone()
        if before is not None and before[0] > 0:
            return False
        self._conn.execute(
            "INSERT INTO event_idempotency (event_id) VALUES (?) ON CONFLICT DO NOTHING",
            [event_id],
        )
        after = self._conn.execute(
            "SELECT COUNT(*) FROM event_idempotency WHERE event_id = ?",
            [event_id],
        ).fetchone()
        return after is not None and after[0] == 1

    def mark_done(self, event_id: str) -> None:
        self._conn.execute(
            "UPDATE event_idempotency SET status = 'done' WHERE event_id = ?",
            [event_id],
        )

    def mark_failed(self, event_id: str) -> None:
        self._conn.execute(
            "UPDATE event_idempotency SET status = 'failed' WHERE event_id = ?",
            [event_id],
        )

